const NORMALIZA_ENTRADA_VERSION = "v3_simples_teste_com_debug_phone";

const firstItem = $input.first()?.json || {};
const input = Array.isArray(firstItem) ? (firstItem[0] || {}) : firstItem;

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function onlyDigits(value) {
  return clean(value).replace(/\D/g, "");
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }
  return "";
}

function nowIso() {
  return new Date().toISOString();
}

function fnv1a64(inputText) {
  const text = String(inputText || "");
  let hash = 1469598103934665603n;

  for (let i = 0; i < text.length; i++) {
    hash ^= BigInt(text.charCodeAt(i));
    hash *= 1099511628211n;
    hash &= (1n << 64n) - 1n;
  }

  return hash;
}

function makeDebugPhone(seed) {
  const hash = fnv1a64(seed);
  const eighteenDigits = String(hash % 1000000000000000000n).padStart(18, "0");
  return `99${eighteenDigits}`.slice(0, 20);
}

const action = firstFilled(input.action, "sendMessage");

const sessionId = firstFilled(
  input.sessionId,
  input.session_id,
  input.chatSessionId,
  `test-${Date.now()}`
);

const chatInput = firstFilled(
  input.chatInput,
  input.message,
  input.text,
  input.content
);

if (!chatInput) {
  throw new Error("chatInput vazio. Envie uma mensagem para testar a Bruna.");
}

const inputPhone = onlyDigits(
  input.phone ||
  input.telefone ||
  input.whatsapp ||
  input.lead?.phone
);

const debugPhone = makeDebugPhone(sessionId);

// No teste, se não vier telefone real, usa telefone fake começando com 99.
const isTest = true;
const phone = isTest ? debugPhone : (inputPhone ? inputPhone.slice(0, 20) : debugPhone);

return [
  {
    json: {
      action,
      sessionId,

      lead: {
        id: sessionId,
        name: firstFilled(input.name, input.nome, input.lead?.name, ""),
        phone
      },

      message: {
        role: "lead",
        content: chatInput,
        has_text: true,
        has_attachment: false,
        created_at: nowIso()
      },

      conversation: {
        is_test: true,
        memory_enabled: true,
        history_source: "agent_memory",
        history_text: ""
      },

      routing: {
        should_reply: true,
        channel: "n8n_chat_test"
      },

      agent: {
        memory_session_id: sessionId
      },

      ai_input: [
        "MENSAGEM ATUAL DO LEAD:",
        chatInput,
        "",
        "CONTEXTO:",
        "Use a memória da conversa vinculada ao sessionId para lembrar mensagens anteriores.",
        "Se não houver memória anterior, trate como primeiro contato.",
        "",
        "INSTRUÇÃO:",
        "Responda como Bruna, atendente virtual da AuAu Creche Canina, seguindo o prompt do agente."
      ].join("\n"),

      debug: {
        normaliza_entrada_version: NORMALIZA_ENTRADA_VERSION,
        received_action: action,
        received_session_id: sessionId,
        received_chat_input: chatInput,
        generated_debug_phone: debugPhone,
        final_phone: phone,
        phone_length: phone.length,
        phone_starts_with_99: phone.startsWith("99"),
        simplified_flow: true,
        memory_expected_in_agent: true
      }
    }
  }
];

parameters.toolDescription:
=A base_conhecimento_bruna é fonte de fatos oficiais da AuAu Creche Canina, não é fonte de decisão conversacional.

Use esta base para confirmar informações operacionais como:
- valores;
- planos;
- pacotes;
- diária;
- mensalidade;
- localização;
- unidades;
- funcionamento da creche;
- funcionamento do hotel;
- avaliação comportamental;
- adaptação;
- regras sanitárias;
- castração;
- cio;
- vacinas;
- antipulgas;
- vermifugação;
- visita;
- material institucional;
- objeções comerciais.

A base pode confirmar fatos, mas quem decide quando falar preço, quando qualificar, quando repassar humano e quando encerrar é o System Prompt da Bruna.

Regra comercial atual sobre preço:
- no primeiro pedido de preço, a Bruna deve qualificar antes e não abrir tabela logo de cara;
- se o lead insistir em preço, a Bruna pode responder valores de forma objetiva;
- se já houver dados suficientes do cão e o lead pedir preço, a Bruna pode responder valores;
- para creche, não abrir tabela completa logo de cara no primeiro pedido;
- para hotel, perguntar o período quando ainda não houver período;
- se houver período e insistência, responder valores de hotel e explicar avaliação/adaptação.

Não use a avaliação como resposta padrão para tudo.
Não responda preço específico apenas porque encontrou preço na base.
Não invente valores, endereços, regras, disponibilidade, exceções, descontos ou condições comerciais.
Nunca retorne chave PIX, CNPJ, recebedor ou dados bancários.

parameters.jsCode:
const NORMALIZA_SAIDA_BRUNA_VERSION = "v2_simples_json_handoff";

const agentItem = $input.first()?.json || {};

let entrada = {};
try {
  entrada = $("Normaliza Entrada Teste").first().json || {};
} catch (error) {
  entrada = {};
}

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function tryParseJson(value) {
  try {
    return JSON.parse(value);
  } catch (error) {
    return null;
  }
}

function extractRawOutput(value) {
  if (value && typeof value === "object") {
    if (value.output !== undefined) return value.output;
    if (value.text !== undefined) return value.text;
    if (value.content !== undefined) return value.content;
  }

  return value;
}

const rawOutput = extractRawOutput(agentItem);
const parsed = typeof rawOutput === "string" ? tryParseJson(rawOutput.trim()) : rawOutput;

let resposta = "";
let handoffHumano = false;
let motivoHandoff = "";

if (parsed && typeof parsed === "object") {
  resposta = clean(parsed.resposta || parsed.reply || parsed.text || parsed.content || "");
  handoffHumano = parsed.handoff_humano === true;
  motivoHandoff = handoffHumano ? clean(parsed.motivo_handoff) : "";
} else {
  resposta = clean(rawOutput);
  handoffHumano = /encaminhar|pessoa da equipe|atendimento humano/i.test(resposta);
  motivoHandoff = handoffHumano ? "inferido_por_texto" : "";
}

if (!resposta) {
  throw new Error("Resposta da Bruna veio vazia.");
}

return [
  {
    json: {
      action: "sendReply",
      sessionId: entrada.sessionId || "",
      lead: entrada.lead || {},
      message_in: entrada.message || {},
      reply: {
        role: "bruna",
        content: resposta,
        created_at: new Date().toISOString()
      },
      handoff: {
        should_handoff: handoffHumano,
        motivo: motivoHandoff,
        responsavel: handoffHumano ? "Flavia" : ""
      },
      routing: {
        should_send: true,
        should_handoff: handoffHumano,
        channel: entrada.routing?.channel || "n8n_chat_test"
      },
      debug: {
        normaliza_saida_bruna_version: NORMALIZA_SAIDA_BRUNA_VERSION,
        agent_raw_output: agentItem,
        parsed_output: parsed || null,
        simplified_flow: true
      }
    }
  }
];

